                    best = vp[i];
                    besti = i;
                }
            }
            if (best > lastbest)
                break;

            start = besti == 0 ? start : p[besti - 1];
            end = besti == NUM - 1 ? end : p[besti + 1];

            pos = p[besti];
            lastbest = best;

